/**
 * Audio Guess track pool — generated by `scripts/fetchAudioTracks.mjs`.
 *
 * Each track has:
 *   - id           slug
 *   - title        canonical answer
 *   - album        album / single name
 *   - year         release year (number)
 *   - answers      lowercase strings the matcher accepts
 *   - preview      /audio-game/<id>.mp3  (30-second iTunes preview)
 *   - cover        /audio-game/<id>.jpg  (600x600 cover)
 *   - spotifySearch  full song search URL on Spotify (for the reveal CTA)
 *   - itunes       provenance fields kept for debugging
 */
import generated from './audioGameTracks.generated.json'

export const audioGameTracks = Array.isArray(generated) ? generated : []

export function getAudioTrackById(id) {
  return audioGameTracks.find((t) => t.id === id) || null
}
